class `data-parser` {
    fun `convert-to-json`(filePath: String): String {
        val csvReader = BufferedReader(InputStreamReader(java.io.File(filePath).readBytes()))
        val lines = csvReader.lines().toList()
        val header = lines[0].split(",").toMutableList()
        val result = mutableListOf<MutableList<String>>()

        for (line in lines.subList(1, lines.size)) {
            val values = line.split(",")
            if (values.size == header.size) {
                val row = header.mapIndexed { index, _ -> values[index] }.toMutableList()
                result.add(row)
            }
        }

        return result.map { it.joinToString(separator = ",") }.joinToString(separator = "\n")
    }
