#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <vector>

class ThreadPool {
public:
    ThreadPool(size_t num_threads);
    ~ThreadPool();

    void addTask(void (*task)(void*), void* arg = nullptr);
    void shutdownNow();

private:
    void* _task_queue;
    std::queue<std::function<void(void*)>> task_queue;
    std::vector<std::thread> threads;
    std::mutex mtx;
    std::condition_variable cv;
    bool stopped = false;

    void _worker_loop(void* arg);
    void _enqueue_task(std::function<void(void*)> task);
};

ThreadPool::ThreadPool(size_t num_threads) : stopped(false) {
    _task_queue = new std::queue<std::function<void(void*)>>();
    for (size_t i = 0; i < num_threads; ++i) {
        threads.emplace_back(_worker_loop, nullptr);
    }
}

ThreadPool::~ThreadPool() {
    {
        std::lock_guard<std::mutex> lock(mtx);
        stopped = true;
    }
    cv.notify_all();
    for (std::thread& thread : threads) {
        thread.join();
    }
    delete _task_queue;
}

void ThreadPool::addTask(void (*task)(void*), void* arg) {
    {
        std::lock_guard<std::mutex> lock(mtx);
        task_queue.push([task, arg](void* arg) { task(arg); });
    }
    cv.notify_one();
}

void ThreadPool::shutdownNow() {
    {
        std::lock_guard<std::mutex> lock(mtx);
        stopped = true;
    }
    cv.notify_all();
}

void ThreadPool::_worker_loop(void* arg) {
    while (true) {
        std::function<void(void*)> task;
        {
            std::unique_lock<std::mutex> lock(mtx);
            cv.wait(lock, [&] { return stopped || !task_queue.empty(); });
            if (stopped && task_queue.empty()) {
                break;
            }
            task = std::move(task_queue.front());
            task_queue.pop();
        }
        if (stopped && task_queue.empty()) {
            break;
        }
        task();
    }
}

void ThreadPool::_enqueue_task(std::function<void(void*)> task) {
    {
        std::lock_guard<std::mutex> lock(mtx);
        task_queue.push(task);
    }
    cv.notify_one();
}
