public class EmailSender {
    private java.util.concurrent.ScheduledFuture<?> scheduledFuture;

    public void sendEmail(String to, String subject, String body) {
        // Implement email sending logic here
        System.out.println("Sending email to " + to + " with subject " + subject + " and body " + body);
    }

    public void scheduleEmail(String to, String subject, String body, long delay) {
        scheduledFuture = java.util.concurrent.Executors.newScheduledThreadPool(1).schedule(() -> {
            sendEmail(to, subject, body);
        }, delay, java.util.concurrent.TimeUnit.SECONDS);
    }

    public void cancelEmail() {
        if (scheduledFuture != null) {
            scheduledFuture.cancel(true);
            scheduledFuture = null;
        }
        System.out.println("Email cancelled");
    }
}
