package fileutil

import (
	"io"
	"os"
	"path/filepath"
	"bufio"
	"encoding/binary"
	"errors"
	"fmt"
)

type FileReader struct {
	f     *os.File
	buf   [4096]byte
	bufR  int
	bufW int
}

func NewFileReader(filename string) (*FileReader, error) {
	f, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	return &FileReader{f: f}, nil
}

func (fr *FileReader) ReadAllLines() ([][]byte, error) {
	var lines [][]byte
	scanner := bufio.NewScanner(fr.f)
	for scanner.Scan() {
		line := scanner.Bytes()
		lines = append(lines, line)
	}
	if err := scanner.Err(); err != nil {
		return nil, err
	}
	return lines, nil
}

func (fr *FileReader) CloseHandle() error {
	if err := fr.f.Close(); err != nil {
		return err
	}
	return nil
}

func (fr *FileReader) DetectEncoding() (encoding, error) {
	encoding, err := fr.f.Header().Get("Content-Encoding")
	if err != nil {
		return "", err
	}
	if encoding == "" {
		return nil, errors.New("encoding not specified")
	}
	switch encoding {
	case "gzip":
		return "gzip", nil
	case "zip":
		return "zip", nil
	case "bz2":
		return "bz2", nil
	default:
		return nil, errors.New("unsupported encoding")
	}
}
