// geometry.rs
pub struct Circle {
    pub radius: f64,
}

impl Circle {
    pub fn new(radius: f64) -> Self {
        assert!(radius > 0.0, "Radius must be greater than zero.");
        Self { radius }
    }

    pub fn calculate_area(&self) -> f64 {
        const PI: f64 = 3.14159265358979323846;
        self.radius.powi(2) * PI
    }

    pub fn set_radius(&mut self, radius: f64) {
        assert!(radius > 0.0, "Radius must be greater than zero.");
        self.radius = radius;
    }

    pub fn collide(&self, other: &dyn Shape) -> bool {
        match other {
            Shape::Circle(other_circle) => {
                let distance = (self.radius as f64).sqrt() + (other_circle.radius as f64).sqrt();
                distance < (self.radius as f64) + (other_circle.radius as f64)
            }
            _ => false,
        }
    }
}

pub trait Shape {
    fn collide(&self, other: &dyn Shape) -> bool;
}

pub struct Rectangle {
    pub x: f64,
    pub y: f64,
    pub w: f64,
    pub h: f64,
}

impl Shape for Rectangle {
    fn collide(&self, other: &dyn Shape) -> bool {
        match other {
            Shape::Circle(circle) => {
                let x = self.x + self.w / 2.0;
                let y = self.y + self.h / 2.0;
                let dx = (x as f64) - (circle.radius as f64);
                let dy = (y as f64) - (circle.radius as f64);
                dx * dx + dy * dy <= circle.radius.powi(2)
            }
            Shape::Rectangle(rect) => {
                let x1 = self.x + self.w / 2.0;
                let y1 = self.y + self.h / 2.0;
                let x2 = self.x + self.w / 2.0 + rect.w;
                let y2 = self.y + self.h / 2.0 + rect.h;
                let x3 = rect.x + rect.w / 2.0;
                let y3 = rect.y + rect.h / 2.0;
                let x4 = rect.x + rect.w / 2.0 + rect.w;
                let y4 = rect.y + rect.h / 2.0 + rect.h;
                (x1 - x3) * (x1 - x3) + (y1 - y3) * (y1 - y3) <= (self.w / 2.0 + rect.w / 2.0) * (self.w / 2.0 + rect.w / 2.0)
                    && (x1 - x4) * (x1 - x4) + (y1 - y4) * (y1 - y4) <= (self.w / 2.0 + rect.w / 2.0) * (self.w / 2.0 + rect.w / 2.0)
                    && (x2 - x3) * (x2 - x3) + (y2 - y3) * (y2 - y3) <= (self.w / 2.0 + rect.w / 2.0) * (self.w / 2.0 + rect.w / 2.0)
                    && (x2 - x4) * (x2 - x4) + (y2 - y4) * (y2 - y4) <= (self.w / 2.0 + rect.w / 2.0) * (self.w / 2.0 + rect.w / 2.0)
            }
            _ => false,
        }
    }
}
