const std = @import("std");

pub fn main() anyerror!void {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    var allocator = gpa.allocator();

    var ini = try IniParser.init(allocator);
    defer ini.deinit();

    try ini.parse("test.ini");
}

const IniParser = struct {
    allocator: std.mem.Allocator,
    current_section: *Section,
    current_line: usize,
    lines: []const u8,

    fn init(allocator: std.mem.Allocator) !IniParser {
        return IniParser{
            .allocator = allocator,
            .current_section = &Section{},
            .current_line = 0,
            .lines = try load_ini_file(allocator, "test.ini"),
        };
    }

    fn deinit(self: *IniParser) void {
        self.current_section = null;
    }

    fn parse(self: *IniParser) anyerror!void {
        for (self.lines) |line| {
            if (line[0] == '[') {
                var section_name: [32]u8 = undefined;
                var i: usize = 1;
                while (i < line.len and line[i] != ']') : (i += 1) {
                    section_name[i - 1] = line[i];
                }
                section_name[i] = '\0';
                self.current_section = try self.allocator.create(Section);
                self.current_section.* = Section{
                    .name = section_name,
                    .keys = try self.allocator.alloc(KeyValuePair, 0),
                };
                self.current_section.keys = try self.allocator.create(KeyValuePair);
                self.current_line = 1;
            } else if (line[0] == ';') {
                self.current_line += 1;
            } else if (line.len > 0 and line[0] == '=') {
                var i: usize = 1;
                while (i < line.len and line[i] != ' ' and line[i] != '\t') : (i += 1) {}
                var key: [32]u8 = undefined;
                var j: usize = i;
                while (j < line.len and line[j] != ' ' and line[j] != '\t') : (j += 1) {
                    key[j - i] = line[j];
                }
                key[j - i] = '\0';

                var value: []u8 = undefined;
                i += 1;
                while (i < line.len and line[i] != ' ' and line[i] != '\t') : (i += 1) {}
                value = line[i..line.len];

                var key_pair: KeyValuePair = .{
                    .key = try self.allocator.dupe(u8, key),
                    .value = try self.allocator.dupe(u8, value),
                };
                if (self.current_section.*.keys.len >= 10) {
                    self.current_section.keys = try self.allocator.reallocation(self.current_section.keys, self.current_section.keys.len + 1);
                }
                self.current_section.keys[self.current_section.keys.len - 1] = key_pair;
            } else if (line.len > 0 and line[0] == '\\') {
                var i: usize = 1;
                while (i < line.len and line[i] != ' ' and line[i] != '\t') : (i += 1) {}
                var value: []u8 = undefined;
                i += 1;
                while (i < line.len and line[i] != ' ' and line[i] != '\t') : (i += 1) {}
                value = line[i..line.len];

                var key: []u8 = undefined;
                i += 1;
                while (i < line.len and line[i] != ' ' and line[i] != '\t') : (i += 1) {}
                key = line[i..line.len];

                var key_pair: KeyValuePair = .{
                    .key = try self.allocator.dupe(u8, key),
                    .value = try self.allocator.dupe(u8, value),
                };
                if (self.current_section.*.keys.len >= 10) {
                    self.current_section.keys = try self.allocator.reallocation(self.current_section.keys, self.current_section.keys.len + 1);
                }
                self.current_section.keys[self.current_section.keys.len - 1] = key_pair;
            } else {
                self.current_line += 1;
            }
        }
    }

    fn load_ini_file(allocator: std.mem.Allocator, filename: []const u8) ![]const u8 {
        var file = try std.fs.cwd().openFile(filename, .{});
        defer file.close();

        var buffer: [1024]u8 = undefined;
        var i: usize = try file.readUntilDelimiterOrEof(buffer[0..], '\n');
        return buffer[0..i];
    }

    fn getValue(self: *IniParser, key: []const u8) !anyerror!i32 {
        var found_key: bool = false;
        for (self.current_section.*.keys) |key_pair| {
            if (key_pair.key == key) {
                if (key_pair.value.len == 10) {
                    var value: i32 = try std.fmt.parseInt(i32, key_pair.value, 10);
                    return value;
                } else if (key_pair.value.len == 4) {
                    var value: bool = try std.fmt.parseInt(bool, key_pair.value, 2);
                    return value;
                } else {
                    return error.InvalidKey;
                }
            }
        }
        return error.KeyNotFound;
    }

    fn addKeyValuePair(self: *IniParser, key: []const u8, value: []const u8) !void {
        var found_key: bool = false;
        for (self.current_section.*.keys) |key_pair| {
            if (key_pair.key == key) {
                if (key_pair.value.len == 10) {
                    var value_int: i32 = try std.fmt.parseInt(i32, key_pair.value, 10);
                    key_pair.value = try std.fmt.parseInt(key_pair.value, 10);
                } else if (key_pair.value.len == 4) {
                    var value_bool: bool = try std.fmt.parseInt(bool, key_pair.value, 2);
                    key_pair.value = try std.fmt.parseInt(key_pair.value, 2);
                } else {
                    continue;
                }
                found_key = true;
                break;
            }
        }
        if (found_key) {
            return;
        }

        var key_pair: KeyValuePair = .{
            .key = try self.allocator.dupe(u8, key),
            .value = try self.allocator.dupe(u8, value),
        };
        if (self.current_section.*.keys.len >= 10) {
            self.current_section.keys = try self.allocator.reallocation(self.current_section.keys, self.current_section.keys.len + 1);
        }
        self.current_section.keys[self.current_section.keys.len - 1] = key_pair;
    }
};

const Section = struct {
    name: []u8,
    keys: []KeyValuePair,
};

const KeyValuePair = struct {
    key: []u8,
    value: []u8,
};

test "IniParser" {
    var ini = try IniParser.init(std.heap.page_allocator);
    defer ini.deinit();

    try ini.parse("test.ini");

    try std.testing.expect(ini.getValue("test") catch |err| err.*);
}
