#include <queue>
#include <mutex>
#include <condition_variable>
#include <stdexcept>
#include <chrono>
#include <thread>

template <typename T>
class ThreadSafeQueue {
private:
    std::queue<T> queue_;
    std::mutex mtx_;
    std::condition_variable cv_;
    size_t maxSize_;

public:
    ThreadSafeQueue(size_t maxSize = 1024)
        : maxSize_(maxSize) {}

    void pushBack(const T& item, std::chrono::milliseconds timeout = std::chrono::milliseconds(0)) {
        std::unique_lock<std::mutex> lock(mtx_);
        while (queue_.size() >= maxSize_) {
            cv_.wait(lock, [this] { return queue_.empty(); });
        }
        queue_.push(item);
        cv_.notify_one();
    }

    T popFront() {
        std::unique_lock<std::mutex> lock(mtx_);
        while (queue_.empty()) {
            cv_.wait(lock, [this] { return !queue_.empty(); });
        }
        T item = std::move(queue_.front());
        queue_.pop();
        return item;
    }
};
