using System;
using System.Diagnostics;
using System.Threading;
using Microsoft.Diagnostics.Process;
using Microsoft.Extensions.Logging;

public class ProcessMonitor
{
    private readonly ILogger _logger;
    private readonly IDiagnosticSource _diagnosticSource;

    public ProcessMonitor(ILogger<ProcessMonitor> logger, IDiagnosticSource diagnosticSource)
    {
        _logger = logger;
        _diagnosticSource = diagnosticSource;
    }

    public event EventHandler<ProcessStartedEventArgs> OnProcessStarted;
    public event EventHandler<ProcessExitedEventArgs> OnProcessExited;

    public void StartProcess(string executablePath, string arguments)
    {
        var process = new Process
        {
            StartInfo =
            {
                FileName = executablePath,
                Arguments = arguments,
                RedirectStandardOutput = true,
                UseShellExecute = false,
                CreateNoWindow = true
            }
        };

        process.Start();

        var processStartedEvent = new ProcessStartedEventArgs(process.Id, process.StartInfo.Arguments);
        OnProcessStarted?.Invoke(this, processStartedEvent);

        _diagnosticSource.AddProcess(process.Id);
    }

    public void StopProcess(int processId)
    {
        var process = Process.GetProcessById(processId);

        if (process != null)
        {
            process.WaitForExit();

            var processExitedEvent = new ProcessExitedEventArgs(process.ExitCode, process.WorkingSet64);
            OnProcessExited?.Invoke(this, processExitedEvent);

            _diagnosticSource.RemoveProcess(process.Id);
        }
    }
}

public class ProcessStartedEventArgs : EventArgs
{
    public int ProcessId { get; set; }
    public string Arguments { get; set; }

    public ProcessStartedEventArgs(int processId, string arguments)
    {
        ProcessId = processId;
        Arguments = arguments;
    }
}

public class ProcessExitedEventArgs : EventArgs
{
    public int ExitCode { get; set; }
    public long WorkingSet64 { get; set; }

    public ProcessExitedEventArgs(int exitCode, long workingSet64)
    {
        ExitCode = exitCode;
        WorkingSet64 = workingSet64;
    }
}
