const std = @import("std");

const PacketDecoder = struct {
    packet: []u8,
    protocol: u16,
    ip_version: u8,
    tcp_port: u16,
    udp_port: u16,

    const Error = error{
        InvalidPacketLength,
        InvalidProtocol,
        InvalidIpVersion,
        InvalidTcpPort,
        InvalidUdpPort,
        MalformedPacket,
    };

    pub fn init(packet: []u8, protocol: u16, ip_version: u8, tcp_port: u16, udp_port: u16) PacketDecoder {
        return PacketDecoder{
            .packet = packet,
            .protocol = protocol,
            .ip_version = ip_version,
            .tcp_port = tcp_port,
            .udp_port = udp_port,
        };
    }

    pub fn readHeader(self: *PacketDecoder) ![]u8 {
        // Read the first 8 bytes of the packet
        var header: [8]u8 = self.packet[0..8];
        // Convert to little-endian
        var result: [8]u8 = try std.mem.endianConvert(
            .LittleEndian,
            header[0..8],
        );
        return result;
    }

    pub fn validateChecksum(self: *PacketDecoder, checksum: u32) bool {
        // Calculate the CRC-32 checksum
        var crc = 0;
        var i: u32 = 0;
        while (i < self.packet.len) : (i += 4) {
            crc = crc32(self.packet[i..i+4], crc);
        }
        // Check if the calculated checksum matches the given checksum
        return crc == checksum;
    }

    fn crc32(data: []u8, crc: u32) u32 {
        var i: u32 = 0;
        while (i < data.len) : (i += 4) {
            crc = crc ^ data[i..i+4];
            for (data[i..i+4]) |byte| {
                crc = crc ^ (byte << (8 * i));
                crc = crc >> 32;
                crc = crc ^ (crc << 32);
            }
        }
        return crc;
    }

    fn validateProtocol(self: *PacketDecoder) Error!void {
        if (self.protocol != 6 and self.protocol != 17) {
            return Error.InvalidProtocol;
        }
    }

    fn validateIpVersion(self: *PacketDecoder) Error!void {
        if (self.ip_version != 4 and self.ip_version != 6) {
            return Error.InvalidIpVersion;
        }
    }

    fn validateTcpPort(self: *PacketDecoder) Error!void {
        if (self.tcp_port < 0 or self.tcp_port > 65535) {
            return Error.InvalidTcpPort;
        }
    }

    fn validateUdpPort(self: *PacketDecoder) Error!void {
        if (self.udp_port < 0 or self.udp_port > 65535) {
            return Error.InvalidUdpPort;
        }
    }

    fn validatePacket(self: *PacketDecoder) Error!void {
        if (self.packet.len < 20) {
            return Error.MalformedPacket;
        }
        if (self.protocol != 6 and self.protocol != 17) {
            return Error.MalformedPacket;
        }
        if (self.ip_version != 4 and self.ip_version != 6) {
            return Error.MalformedPacket;
        }
        if (self.tcp_port < 0 or self.tcp_port > 65535) {
            return Error.MalformedPacket;
        }
        if (self.udp_port < 0 or self.udp_port > 65535) {
            return Error.MalformedPacket;
        }
    }
};

