const std = @import("std");

pub const PixelMatrix = struct {
    height: u32,
    width: u32,
    depth: u16,
    buffer: [height * width * depth]u8,

    fn init(height: u32, width: u32, depth: u16) PixelMatrix {
        return PixelMatrix{
            .height = height,
            .width = width,
            .depth = depth,
            .buffer = undefined,
        };
    }

    fn deinit(self: *PixelMatrix) void {
        self.buffer = undefined;
    }

    fn convertToGrayscale(self: *PixelMatrix, scale: f32) !void {
        var i: u32 = 0;
        var j: u32 = 0;
        var k: u16 = 0;

        for (self.buffer) |*, w| {
            for (w) |*, b| {
                for (b) |*, v| {
                    k += v;
                }
                k /= self.depth;
                self.buffer[i * self.width * self.depth + j * self.depth + k] = k * scale;
                k = 0;
            }
            j += 1;
            k = 0;
        }
        self.height -= 1;
        self.width -= 1;
    }

    fn applyKernel(self: *PixelMatrix, kernel: []f32, mode: u8) !void {
        var i: u32 = 0;
        var j: u32 = 0;
        var k: u16 = 0;

        for (kernel) |k, i| {
            if (i == 0) continue;
            if (i == kernel.len) continue;

            var kernel_len: u32 = kernel.len - 1;
            var kernel_i: u32 = i - kernel_len / 2;
            var kernel_j: u32 = j - kernel_len / 2;

            for (self.buffer) |*, w| {
                for (w) |*, b| {
                    for (b) |*, v| {
                        k += v * kernel[i];
                    }
                    k /= self.depth;
                    self.buffer[i * self.width * self.depth + j * self.depth + k] = k;
                    k = 0;
                }
                j += 1;
                k = 0;
            }
            j = kernel_j + 1;
            k = 0;
        }
        self.height -= 1;
        self.width -= 1;
    }

    fn anisotropicDiffusion(self: *PixelMatrix, iterations: u32) !void {
        for (iterations) |i| {
            self.convertToGrayscale(1.0 / 2.0);
            self.applyKernel(&@intToFloat(f32, 1.0), 0); // Sobel
            self.applyKernel(&@intToFloat(f32, -1.0), 1); // Prewitt
        }
    }
};

