import json
import xml.etree.ElementTree as ET
import csv
import time
import hashlib
import hmac
import base64
from functools import wraps
from enum import Enum
from typing import Dict, Any
from abc import ABC, abstractmethod
from cachetools import TTLCache
from charset_normalizer import to_ascii
import asyncio

class DataTransformer(ABC):
    def __init__(self, schema: Dict[str, Any], ttl: int):
        self.schema = schema
        self.ttl = ttl
        self.cache = TTLCache(maxsize=1000, ttl=ttl)
        self.encrypted_fields = {}

    @abstractmethod
    async def convert_to_format(self, data: Dict[str, Any]) -> Any:
        pass

    async def validate_input(self, data: Dict[str, Any]) -> bool:
        ascii_data = to_ascii(data)
        return ascii_data == data

    async def cache_processed_data(self, data: Dict[str, Any], key: str) -> Any:
        try:
            return self.cache[key]
        except KeyError:
            pass
        encrypted_data = {}
        for field, value in data.items():
            if field in self.encrypted_fields:
                encrypted_data[field] = await self.encrypt(value)
            else:
                encrypted_data[field] = value
        encrypted_data = await self.validate_input(encrypted_data)
        await self.cache[key] = encrypted_data
        return encrypted_data

    async def encrypt(self, value: Any) -> str:
        if value is None:
            return value
        return hmac.new(b'secret_key', str(value).encode(), hashlib.sha256).hexdigest()


class JSONTransformer(DataTransformer):
    async def convert_to_format(self, data: Dict[str, Any]) -> str:
        return json.dumps(data, indent=4, default=str)


class XMLTransformer(DataTransformer):
    async def convert_to_format(self, data: Dict[str, Any]) -> str:
        root = ET.Element('root')
        for field, value in data.items():
            child = ET.SubElement(root, field)
            child.text = str(value)
        return ET.tostring(root, encoding='unicode')


class CSVTransformer(DataTransformer):
    async def convert_to_format(self, data: Dict[str, Any]) -> str:
        writer = csv.writer(sys.stdout)
        writer.writerow(list(data.keys()))
        for field, value in data.items():
            writer.writerow([field, str(value)])
        return sys.stdout.getvalue()


async def main(data: Dict[str, Any]):
    transformer = JSONTransformer({'name': 'John', 'age': 30}, 60)
    processed_data = await transformer.cache_processed_data(data, 'json_data')
    await transformer.convert_to_format(processed_data)
    await asyncio.sleep(61)
    await transformer.convert_to_format(processed_data)


if __name__ == '__main__':
    data = {'name': 'John', 'age': 30}
    asyncio.run(main(data))
