            isOpen = false;
        }
    }

    public class RetryConfigImpl implements RetryConfig {

        private final long initialDelay;
        private final long maxDelay;
        private final int maxAttempts;

        public RetryConfigImpl(long initialDelay, long maxDelay, int maxAttempts) {
            this.initialDelay = initialDelay;
            this.maxDelay = maxDelay;
            this.maxAttempts = maxAttempts;
        }

        @Override
        public long getInitialDelay() {
            return initialDelay;
        }

        @Override
        public long getMaxDelay() {
            return maxDelay;
        }

        @Override
        public int getMaxAttempts() {
            return maxAttempts;
        }

        public Supplier<HttpRequest> getRetryFunction() {
            return () -> {
                long delay = ThreadLocalRandom.current().nextLong(initialDelay, maxDelay);
                try {
                    Thread.sleep(delay);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
                return request();
            };
        }
    }

