const { protobuf } = require('protobufjs');
const { EventEmitter } = require('events');

class WebSocketManager extends EventEmitter {
  constructor(options = {}) {
    super();
    this.options = options;
    this.config = {
      ...options.config,
      // Add configuration properties here
    };
    this.connections = {};
    this.subscriptions = {};
    this.heartbeatInterval = null;
    this.reconnectTimeout = null;
  }

  init() {
    this.connect();
    this.startHeartbeat();
    this.startReconnect();
  }

  connect() {
    const url = this.config.url;
    const protocol = this.config.protocol;
    const reconnectDelay = this.config.reconnectDelay;
    const reconnectAttempts = this.config.reconnectAttempts;

    const options = {
      protocol,
      path: this.config.path,
      maxPayloadSize: this.config.maxPayloadSize,
    };

    this.connecting = true;
    this.connections[url] = new WebSocket(url, options);

    this.connections[url].on('open', () => {
      this.onConnectionOpen(url);
    });

    this.connections[url].on('close', () => {
      this.onConnectionClose(url);
    });

    this.connections[url].on('error', (error) => {
      this.onConnectionError(url, error);
    });

    this.connections[url].on('message', (message) => {
      this.onMessage(url, message);
    });
  }

  startHeartbeat() {
    this.heartbeatInterval = setInterval(() => {
      this.sendHeartbeat();
    }, this.config.heartbeatInterval);
  }

  sendHeartbeat() {
    const url = Object.keys(this.connections)[0];
    const message = {
      type: 'heartbeat',
    };
    this.connections[url].send(JSON.stringify(message));
  }

  startReconnect() {
    this.reconnectTimeout = setInterval(() => {
      this.reconnect();
    }, this.config.reconnectTimeout);
  }

  reconnect() {
    const url = Object.keys(this.connections)[0];
    if (this.connections[url].readyState === 0) {
      this.connect();
    } else {
      const reconnectDelay = this.config.reconnectDelay;
      const reconnectAttempts = this.config.reconnectAttempts;
      const currentDelay = this.config.reconnectTimeout - (this.config.reconnectTimeout - reconnectDelay);
      this.reconnectTimeout = setTimeout(() => {
        this.reconnect();
      }, currentDelay);
    }
  }

  onConnectionOpen(url) {
    this.emit('connectionOpen', url);
  }

  onConnectionClose(url) {
    this.emit('connectionClose', url);
  }

  onConnectionError(url, error) {
    this.emit('connectionError', url, error);
  }

  onMessage(url, message) {
    this.emit('message', url, message);
  }

  subscribe(url, topic) {
    if (!this.subscriptions[url]) {
      this.subscriptions[url] = {};
    }
    if (!this.subscriptions[url][topic]) {
      this.subscriptions[url][topic] = [];
    }
    this.subscriptions[url][topic].push(message => {
      this.emit('message', url, message);
    });
  }

  unsubscribe(url, topic) {
    if (this.subscriptions[url]) {
      if (this.subscriptions[url][topic]) {
        delete this.subscriptions[url][topic];
      }
    }
  }

  send(message) {
    const url = Object.keys(this.connections)[0];
    const compressedMessage = protobuf.encode(message).toString('base64');
    this.connections[url].send(compressedMessage);
  }

  validateMessage(message) {
    const schema = this.config.messageSchema;
    const isValid = protobuf.validate(message, schema);
    if (!isValid) {
      throw new Error('Invalid message');
    }
  }

  static fromConfig(config) {
    return new WebSocketManager(config);
  }
}

module.exports = WebSocketManager;
