use aes_gcm::AesGcm;
use base64;
use crypto::Digest;
use crypto::Hmac;
use crypto::Key;
use crypto::Mac;
use crypto::Sha256;
use crypto::Symmetric;
use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use rand::Rng;

// Constants
const AES_KEY_SIZE: usize = 256;
const AES_IV_SIZE: usize = 12;
const KEY_SIZE: usize = AES_KEY_SIZE;
const IV_SIZE: usize = AES_IV_SIZE;

// SecureStorage struct
pub struct SecureStorage {
    key: Arc<Mutex<Key>>,
    iv: Arc<Mutex<Vec<u8>>>,
}

impl SecureStorage {
    // Create a new SecureStorage instance
    pub fn new() -> Self {
        let key = Arc::new(Mutex::new(Key::generate(KEY_SIZE)));
        let iv = Arc::new(Mutex::new(Vec::new()));

        Self { key, iv }
    }

    // Store encrypted key-value pair
    pub fn store_data(&self, key: &str, value: &str) {
        let key = self.key.lock().unwrap();
        let iv = self.iv.lock().unwrap();

        let mut rng = rand::thread_rng();
        iv.extend_from_slice(&[rng.gen::<u8>(); AES_IV_SIZE]);

        let key = key.as_ref();
        let iv = iv.as_ref();

        let cipher = AesGcm::new(key, iv);
        let tag = cipher.encrypt_and_tag(value.as_bytes(), Digest::Sha256, None).unwrap();

        let encrypted_value = base64::encode(cipher.finalize(value.as_bytes(), Digest::Sha256, None).unwrap());

        println!("Storing key-value pair: key={}", key);
        println!("Storing encrypted value: {}", encrypted_value);

        let mut storage = HashMap::new();
        storage.insert(key.to_string(), encrypted_value.to_string());
        println!("Storage: {:?}", storage);
    }

    // Retrieve encrypted key-value pair
    pub fn retrieve_data(&self, key: &str) -> Option<String> {
        let key = self.key.lock().unwrap();
        let storage = self.storage.lock().unwrap();

        if storage.contains_key(key) {
            let encrypted_value = storage.get(key).unwrap().clone();

            println!("Retrieving key-value pair: key={}", key);
            println!("Encrypted value: {}", encrypted_value);

            let cipher = AesGcm::new(key.as_ref(), self.iv.lock().unwrap());
            let decrypted_value = cipher.decrypt_and_verify(encrypted_value.as_bytes(), Digest::Sha256, None).unwrap();

            println!("Decrypted value: {}", String::from_utf8_lossy(&decrypted_value));

            Some(String::from_utf8_lossy(&decrypted_value).to_string())
        } else {
            None
        }
    }

    // Delete key-value pair
    pub fn delete_data(&self, key: &str) {
        let key = self.key.lock().unwrap();
        let storage = self.storage.lock().unwrap();

        if storage.contains_key(key) {
            storage.remove(key);
            println!("Deleted key-value pair: key={}", key);
        } else {
            println!("Key-value pair not found: key={}", key);
        }
    }

    // Private storage field
    fn storage(&self) -> Arc<Mutex<HashMap<String, String>>> {
        Arc::new(Mutex::new(HashMap::new()))
    }
}

fn main() {
    let storage = SecureStorage::new();
    storage.store_data("user_id", "12345");
    storage.retrieve_data("user_id");
    storage.delete_data("user_id");
}
