package fileManager

import (
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"sync"
)

// FileManager represents a file manager package for cloud storage.
type FileManager struct {
	store    map[string][]byte
	mu       sync.Mutex
	url      string
}

// NewFileManager returns a new instance of FileManager.
func NewFileManager(url string) *FileManager {
	return &FileManager{
		store:    make(map[string][]byte),
		url:      url,
	}
}

// UploadFile uploads a file to the cloud storage.
func (fm *FileManager) UploadFile(filename string, data []byte) error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	if _, ok := fm.store[filename]; ok {
		return fmt.Errorf("file %s already exists", filename)
	}

	fm.store[filename] = data

	return nil
}

// DownloadFile retrieves a stored file from the cloud storage.
func (fm *FileManager) DownloadFile(filename string) (io.Reader, error) {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	data, ok := fm.store[filename]
	if !ok {
		return nil, fmt.Errorf("file %s not found", filename)
	}

	return bytes.NewReader(data), nil
}

// DeleteFile removes a file from the cloud storage.
func (fm *FileManager) DeleteFile(filename string) error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	delete(fm.store, filename)
	return nil
}

// SaveFiles saves all stored files to disk.
func (fm *FileManager) SaveFiles() error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	for filename, data := range fm.store {
		err := SaveFile(filename, data)
		if err != nil {
			return err
		}
	}

	return nil
}

// LoadFiles loads all stored files from disk.
func (fm *FileManager) LoadFiles() error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	fm.store = make(map[string][]byte)

	return LoadFilesFromDisk()
}

func SaveFile(filename string, data []byte) error {
	f, err := os.Create(filename)
	if err != nil {
		return err
	}
	defer f.Close()

	_, err = f.Write(data)
	return err
}

func LoadFilesFromDisk() error {
	files, err := os.ReadDir(".")
	if err != nil {
		return err
	}

	for _, file := range files {
		if file.IsDir() {
			continue
		}

		f, err := os.Open(file.Name())
		if err != nil {
			return err
		}
		defer f.Close()

		var data []byte
		_, err = io.ReadAll(f)
		if err != nil {
			return err
		}

		fm := NewFileManager(fm.url)
		fm.store = fm.store
		fm.store[file.Name()] = data
	}
	return nil
}
