#include <iostream>
#include <fstream>
#include <sstream>
#include <vector>
#include <map>
#include <stdexcept>

class LogAnalyzer {
public:
    LogAnalyzer(const std::string& logFilePath) : logFilePath_(logFilePath) {}

    void parseLog() {
        std::ifstream logFile(logFilePath_);
        if (!logFile.is_open()) {
            throw std::runtime_error("Failed to open log file");
        }

        std::vector<std::string> logEntries;
        std::string line;
        while (std::getline(logFile, line)) {
            logEntries.push_back(line);
        }
        logFile.close();

        entries_.clear();
        for (const auto& entry : logEntries) {
            parseEntry(entry);
        }
    }

    void filterEntries(const std::string& severity) {
        if (severity != "INFO" && severity != "WARNING" && severity != "ERROR") {
            throw std::invalid_argument("Invalid severity level");
        }

        entries_.clear();
        for (const auto& entry : entries_) {
            if (filterEntry(entry, severity)) {
                entries_.push_back(entry);
            }
        }
    }

    void generateReport() {
        std::map<std::string, int> report;
        for (const auto& entry : entries_) {
            const auto& parts = splitEntry(entry);
            if (parts.size() >= 2) {
                report[parts[0]]++;
            }
        }

        for (const auto& pair : report) {
            std::cout << pair.first << ": " << pair.second << std::endl;
        }
    }

private:
    std::string logFilePath_;
    std::vector<std::string> entries_;

    void parseEntry(const std::string& entry) {
        size_t spacePos = entry.find(' ');
        if (spacePos == std::string::npos) {
            return;
        }

        std::string level = entry.substr(0, spacePos);
        std::string message = entry.substr(spacePos + 1);

        if (level == "INFO") {
            severity_ = "INFO";
        } else if (level == "WARNING") {
            severity_ = "WARNING";
        } else if (level == "ERROR") {
            severity_ = "ERROR";
        }

        entries_.push_back(message);
    }

    bool filterEntry(const std::string& entry, const std::string& severity) {
        if (severity == "INFO" && entry.find("ERROR") != std::string::npos) {
            return false;
        }
        if (severity == "WARNING" && entry.find("INFO") != std::string::npos) {
            return false;
        }
        if (severity == "ERROR" && entry.find("WARNING") != std::string::npos) {
            return false;
        }
        return true;
    }

    std::vector<std::string> splitEntry(const std::string& entry) {
        size_t spacePos = entry.find(' ');
        if (spacePos == std::string::npos) {
            return {entry};
        }
        return {entry.substr(0, spacePos), entry.substr(spacePos + 1)};
    }

    std::string severity_;
};

int main() {
    LogAnalyzer analyzer("path_to_log_file.log");
    analyzer.parseLog();
    analyzer.filterEntries("INFO");
    analyzer.generateReport();
    return 0;
}
