use std::fs::{File, OpenOptions};
use std::io::{Read, Write};
use std::path::Path;
use std::sync::{Arc, Mutex};
use zip::ZipArchive;
use zip::ZipFile;
use lz4::{compress, decompress};
use bzip2::read::Bzip2Decoder;
use bzip2::write::Bzip2Encoder;
use gzip::{GzDecoder, GzEncoder};
use std::thread;

pub struct FileCompressor {
    algorithms: Arc<Mutex<Vec<String>>>,
}

impl FileCompressor {
    pub fn new() -> Self {
        Self {
            algorithms: Arc::new(Mutex::new(vec!["gzip".to_string(), "bzip2".to_string(), "lz4".to_string()]),
        }
    }

    pub fn compress_file(&self, file_path: &str, compression_type: &str) -> Result<(), std::io::Error> {
        let file = File::open(file_path)?;
        let mut file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .open(file_path)?;

        match compression_type {
            "gzip" => self.gzip_compression(&mut file),
            "bzip2" => self.bzip2_compression(&mut file),
            "lz4" => self.lz4_compression(&mut file),
            _ => return Err(std::io::Error::new(std::io::ErrorKind::InvalidData, "Unsupported compression type")),
        }

        Ok(())
    }

    pub fn decompress_file(&self, compressed_file_path: &str, decompression_type: &str) -> Result<(), std::io::Error> {
        let file = File::open(compressed_file_path)?;

        match decompression_type {
            "gzip" => self.gzip_decompression(file),
            "bzip2" => self.bzip2_decompression(file),
            "lz4" => self.lz4_decompression(file),
            _ => return Err(std::io::Error::new(std::io::ErrorKind::InvalidData, "Unsupported decompression type")),
        }

        Ok(())
    }

    fn gzip_compression(&self, mut file: impl Write) -> Result<(), std::io::Error> {
        let mut gzip_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp.gz")?;

        let mut gzip_encoder = GzEncoder::new(gzip_file, std::io::BufWriter::new(gzip_file));
        file.rewind()?;
        gzip_encoder.write_all(&file.read_to_end()?)?;
        gzip_file.flush()?;
        drop(gzip_encoder);

        Ok(())
    }

    fn gzip_decompression(&self, mut file: impl Read) -> Result<(), std::io::Error> {
        let mut gzip_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp.gz")?;

        let mut gzip_decoder = GzDecoder::new(file);
        let mut decompressed_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp")?;

        gzip_decoder.read_to_end(&mut decompressed_file)?;
        decompressed_file.flush()?;
        drop(gzip_decoder);

        Ok(())
    }

    fn bzip2_compression(&self, mut file: impl Write) -> Result<(), std::io::Error> {
        let mut bzip2_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp")?;

        let mut bzip2_encoder = Bzip2Encoder::new(bzip2_file, std::io::BufWriter::new(bzip2_file));
        file.rewind()?;
        bzip2_encoder.write_all(&file.read_to_end()?)?;
        bzip2_file.flush()?;
        drop(bzip2_encoder);

        Ok(())
    }

    fn bzip2_decompression(&self, mut file: impl Read) -> Result<(), std::io::Error> {
        let mut bzip2_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp")?;

        let mut bzip2_decoder = Bzip2Decoder::new(file);
        let mut decompressed_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp")?;

        bzip2_decoder.read_to_end(&mut decompressed_file)?;
        decompressed_file.flush()?;
        drop(bzip2_decoder);

        Ok(())
    }

    fn lz4_compression(&self, mut file: impl Write) -> Result<(), std::io::Error> {
        let mut lz4_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp")?;

        let mut lz4_encoder = lz4::compress::Builder::new()
            .build()
            .unwrap()
            .compress(&mut lz4_file, &mut file);
        file.rewind()?;
        lz4_encoder.write_all(&file.read_to_end()?)?;
        lz4_file.flush()?;
        drop(lz4_encoder);

        Ok(())
    }

    fn lz4_decompression(&self, mut file: impl Read) -> Result<(), std::io::Error> {
        let mut lz4_file = OpenOptions::new()
            .read(true)
            .write(true)
            .create(true)
            .append(true)
            .open("temp")?;

        let mut lz4_decoder = lz4::decompress::Builder::new()
            .build()
            .unwrap()
            .decompress(&mut lz4_file, &mut file);
        file.flush()?;
        drop(lz4_decoder);

        Ok(())
    }
