from concurrent.futures import ThreadPoolExecutor

class DataPipeline:
    def __init__(self, data_sources):
        self.data_sources = data_sources
        self.data = {}

    def extract_data(self, source, file_path):
        if source == 'csv':
            self.data[source] = pd.read_csv(file_path)
        elif source == 'json':
            with open(file_path, 'r') as f:
                self.data[source] = json.load(f)
        elif source == 'database':
            conn = sqlite3.connect(file_path)
            self.data[source] = pd.read_sql_query('SELECT * FROM table_name', conn)
            conn.close()

    def transform_data(self, source, data):
        if source == 'csv':
            data = data.applymap(lambda x: str(x) if isinstance(x, float) else x)
        elif source == 'json':
            data = json.dumps(data, indent=4)
        elif source == 'database':
            data = data.astype(str)
        return data

    def load_data(self, source, transformed_data):
        if source == 'csv':
            transformed_data.to_csv('output.csv', index=False)
        elif source == 'json':
            with open('output.json', 'w') as f:
                f.write(transformed_data)
        elif source == 'database':
            conn = sqlite3.connect('output.db')
            transformed_data.to_sql('table_name', conn, if_exists='replace', index=False)
            conn.close()

    def run_pipeline(self):
        with ThreadPoolExecutor() as executor:
            executor.map(self.extract_data, self.data_sources, ['data.csv', 'data.json', 'data.db'])
            executor.map(self.transform_data, self.data_sources, [self.data[source] for source in self.data_sources])
            executor.map(self.load_data, self.data_sources, [self.transform_data(source, self.data[source]) for source in self.data_sources])
