from abc import ABC, abstractmethod
from typing import Dict, List

class ParsedResponse:
    def __init__(self, data: Dict):
        self.data = data

class APIException(Exception):
    pass

class api_client(ABC):
    def __init__(self, config: Dict):
        self.config = config
        self.rate_limit = 0
        self.backoff = 0

    @abstractmethod
    def get_transaction_graph(self, transaction_hash: str) -> ParsedResponse:
        pass

    def post_smart_contract(self, contract_abi: List[Dict], contract_address: str, function_name: str, function_params: List[Dict]) -> ParsedResponse:
        url = f"{self.config['endpoint']}/{self.config['contract_address']}/{function_name}"
        headers = {"Content-Type": "application/json"}
        data = {
            "contractAbi": contract_abi,
            "functionName": function_name,
            "functionParams": function_params
        }
        response = self._make_request(url, headers, data)
        if response.status_code == 200:
            return ParsedResponse(response.json())
        else:
            raise APIException(f"Failed to post to smart contract. Status code: {response.status_code}")

    def _make_request(self, url: str, headers: Dict, data: Dict) -> requests.Response:
        if self.rate_limit > 0:
            time.sleep(self.backoff)
            self.backoff *= 2
            self.rate_limit -= 1
        else:
            self.rate_limit = 5
            self.backoff = 1
        response = requests.post(url, headers=headers, json=data)
        self.rate_limit = 5
        self.backoff = 1
        return response

    def handle_rate_limiting(self, response: requests.Response):
        if response.status_code >= 500:
            raise APIException("Rate limit exceeded")
