// NetworkMonitor is a struct to monitor network activity
type NetworkMonitor struct {
    trafficMap map[string]uint64
    activeConnections map[string]bool
    logLock sync.RWMutex
    logFile  *log.File
}

// NewNetworkMonitor returns a new instance of NetworkMonitor
func NewNetworkMonitor(logFile *log.File) *NetworkMonitor {
    return &NetworkMonitor{
        trafficMap: make(map[string]uint64),
        activeConnections: make(map[string]bool),
        logFile: logFile,
    }
}

// monitorTraffic measures bandwidth usage and updates the traffic map
func (nm *NetworkMonitor) monitorTraffic(src, dst string, bandwidth uint64) {
    nm.logLock.Lock()
    defer nm.logLock.Unlock()
    nm.trafficMap[src] += bandwidth
    nm.trafficMap[dst] += bandwidth
    log.Println("Traffic measured: ", src, " -> ", dst, " bandwidth: ", bandwidth)
}

// detectIntrusion detects active connections and updates the active connections map
func (nm *NetworkMonitor) detectIntrusion(src, dst string) bool {
    nm.logLock.Lock()
    defer nm.logLock.Unlock()
    if nm.activeConnections[src] {
        return true
    }
    nm.activeConnections[src] = true
    nm.activeConnections[dst] = true
    return false
}

// logActivity logs network anomalies and updates the log file
func (nm *NetworkMonitor) logActivity(anomaly string) {
    nm.logLock.Lock()
    defer nm.logLock.Unlock()
    nm.logFile.Println(anomaly)
}

func main() {
    logFile, err := log.Open("network.log", false, log.LstdFlags|log.Lshortfile)
    if err != nil {
        log.Fatal(err)
    }
    nm := NewNetworkMonitor(logFile)
    nm.monitorTraffic("192.168.1.1", "192.168.1.2", 1000)
    nm.detectIntrusion("192.168.1.1", "192.168.1.2")
    nm.logActivity("Intrusion detected")
}
