// GeoFence.java
import java.util.ArrayList;
import java.util.List;

import org.apache.commons.math3.geometry.euclidean.threed.Vector3D;
import org.apache.commons.math3.geometry.euclidean.threed.Vector3DUtils;

public class GeoFence {
    private List<Point3D> points;
    private double boundaryRadius;
    private double accuracyThresholdLow;
    private double accuracyThresholdHigh;

    public GeoFence(List<Point3D> points) {
        this.points = points;
        this.boundaryRadius = calculateBoundaryRadius(points);
        this.accuracyThresholdLow = "LOW";
        this.accuracyThresholdHigh = "HIGH";
    }

    private double calculateBoundaryRadius(List<Point3D> points) {
        double minLat = Double.MAX_VALUE;
        double maxLat = Double.MIN_VALUE;
        double minLng = Double.MAX_VALUE;
        double maxLng = Double.MIN_VALUE;

        for (Point3D point : points) {
            if (point.lat < minLat) {
                minLat = point.lat;
            }
            if (point.lat > maxLat) {
                maxLat = point.lat;
            }
            if (point.lng < minLng) {
                minLng = point.lng;
            }
            if (point.lng > maxLng) {
                maxLng = point.lng;
            }
        }

        double centerLat = (minLat + maxLat) / 2;
        double centerLng = (minLng + maxLng) / 2;

        double distance = calculateHaversineDistance(centerLat, centerLng, minLat, minLng);
        return distance;
    }

    private double calculateHaversineDistance(double lat1, double lng1, double lat2, double lng2) {
        double earthRadius = 6371;
        double dLat = Math.toRadians(lat2 - lat1);
        double dLng = Math.toRadians(lng2 - lng1);
        double lat1Rad = Math.toRadians(lat1);
        double lat2Rad = Math.toRadians(lat2);

        double a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
                Math.sin(dLng / 2) * Math.sin(dLng / 2) * Math.cos(lat1Rad) * Math.cos(lat2Rad);
        double c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
        return earthRadius * c;
    }

    public boolean checkWithinBoundary(Point3D point) {
        double distance = calculateHaversineDistance(point.lat, point.lng, boundaryRadius, boundaryRadius);
        return distance <= accuracyThresholdLow || distance <= accuracyThresholdHigh;
    }

    public List<Point3D> optimizeClusters(List<Point3D> points) {
        kMeans(points);
        return points;
    }

    private void kMeans(List<Point3D> points) {
        // k-means implementation
        // for simplicity, this is a basic implementation
        // and does not include error checking or handling
        int k = 3;
        int iterations = 10;
        List<List<Point3D>> clusters = initializeClusters(points, k);

        for (int i = 0; i < iterations; i++) {
            assignPointsToClusters(points, clusters, k);
            updateCentroids(clusters, k);
            if (isConverged(clusters, k)) {
                break;
            }
        }

        return clusters.get(0);
    }

    private List<List<Point3D>> initializeClusters(List<Point3D> points, int k) {
        List<List<Point3D>> clusters = new ArrayList<>();
        for (int i = 0; i < k; i++) {
            clusters.add(new ArrayList<>());
        }

        for (Point3D point : points) {
            int clusterIndex = Math.floorMod(i, k);
            clusters.get(clusterIndex).add(point);
        }

        return clusters;
    }

    private void assignPointsToClusters(List<Point3D> points, List<List<Point3D>> clusters, int k) {
        for (Point3D point : points) {
            int clusterIndex = Math.floorMod(Math.floorDiv(Math.floorMod(point.lat, 360), 360) + Math.floorMod(point.lng, 360), k);
            clusters.get(clusterIndex).add(point);
        }
    }

    private void updateCentroids(List<List<Point3D>> clusters, int k) {
        for (int i = 0; i < k; i++) {
            double sumLat = 0;
            double sumLng = 0;
            for (Point3D point : clusters.get(i)) {
                sumLat += point.lat;
                sumLng += point.lng;
            }
            double centroidLat = sumLat / clusters.get(i).size();
            double centroidLng = sumLng / clusters.get(i).size();
            clusters.get(i).clear();
            clusters.get(i).add(new Point3D(centroidLat, centroidLng, 0));
        }
    }

    private boolean isConverged(List<List<Point3D>> clusters, int k) {
        for (int i = 0; i < k; i++) {
            if (clusters.get(i).size() == 0) {
                return false;
            }
        }

        for (int i = 0; i < k; i++) {
            for (int j = i + 1; j < k; j++) {
                double distance = calculateHaversineDistance(clusters.get(i).get(0).lat, clusters.get(i).get(0).lng, clusters.get(j).get(0).lat, clusters.get(j).get(0).lng);
                if (distance > 0.1) {
                    return false;
                }
            }
        }

        return true;
    }
